import React, { useContext } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { AuthCtx } from '../context/AuthContext';

const Navbar = () => {
  const { authToken, currentUser, logout } = useContext(AuthCtx);
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  return (
    <nav id="navbar">
      <div className="logo" onClick={() => navigate('/')}>VoteFor<span>Change</span></div>
      {!authToken ? (
        <div className="nav-links">
          <Link to="/" className="nav-link">Home</Link>
          <Link to="/" className="nav-link">About</Link>
          <Link to="/Service" className="nav-link">Features</Link>
          <Link to="/Contact" className="nav-link">Contact Us</Link>
          <Link to="/Login" className="btn-nav-login" style={{textDecoration:'none'}}>Login</Link>
        </div>
      ) : (
        <div className="nav-links">
          <span style={{ fontWeight: 500 }}>Voter ID: {currentUser}</span>
          <button onClick={handleLogout} className="btn-secondary" style={{ borderRadius: '20px', padding: '8px 20px' }}>Logout</button>
        </div>
      )}
    </nav>
  );
};

export default Navbar;
